def get_arch_overview(result):
    """
    銆愭覆鏌撳尯鍩熴€戝熀鏈俊鎭笌瓒冲紦鎸囨爣 (StandingReport.jsx #overview)
    瓒冲紦鎸囨暟銆佽冻寮撶被鍨嬨€佽冻閮ㄥ昂瀵搞€侀潰绉瓑

    杩斿洖: {
        'left': {
            'archIndex': float,       # 瓒冲紦鎸囨暟 (0.21~0.26涓烘甯?
            'archType': str,          # 瓒冲紦绫诲瀷 (Normal/High/Flat)
            'clarkeAngle': float,     # Clarke瑙?
            'clarkeType': str,        # Clarke鍒嗙被
            'staheliRatio': float,    # Staheli姣斿€?
            'length': float,          # 瓒抽暱(cm)
            'width': float,           # 瓒冲(cm)
            'totalArea': float,       # 鎬婚潰绉?cm虏)
            'forefootArea': float,    # 鍓嶈冻闈㈢Н(cm虏)
            'midfootArea': float,     # 涓冻闈㈢Н(cm虏)
            'hindfootArea': float,    # 鍚庤冻闈㈢Н(cm虏)
        },
        'right': { ... 鍚屼笂 },
    }
    鍓嶇娓叉煋: 宸﹀彸鑴氬姣旇〃鏍?鍗＄墖
    """
    arch = result.get('arch_features', {})
    ad = result.get('additional_data', {})
    la = ad.get('left_area', {})
    ra = ad.get('right_area', {})
    left_foot = arch.get('left_foot', {})
    right_foot = arch.get('right_foot', {})

    def build_foot(foot, area, length_key, width_key):
        return {
            'archIndex': foot.get('area_index'),
            'archType': foot.get('area_type'),
            'clarkeAngle': foot.get('clarke_angle'),
            'clarkeType': foot.get('clarke_type'),
            'staheliRatio': foot.get('staheli_ratio'),
            'length': ad.get(length_key, 0),
            'width': ad.get(width_key, 0),
            'totalArea': area.get('total_area_cm2', 0),
            'forefootArea': (area.get('area_cm2') or [0, 0, 0])[0],
            'midfootArea': (area.get('area_cm2') or [0, 0, 0])[1],
            'hindfootArea': (area.get('area_cm2') or [0, 0, 0])[2],
        }

    return {
        'left': build_foot(left_foot, la, 'left_length', 'left_width'),
        'right': build_foot(right_foot, ra, 'right_length', 'right_width'),
    }


def get_pressure_distribution(result):
    """
    銆愭覆鏌撳尯鍩熴€戝尯鍩熷帇鍔涘垎甯?(StandingReport.jsx #pressure)
    鍓嶈冻/涓冻/鍚庤冻鐨勫帇鍔涘崰姣?

    杩斿洖: {
        'left': {
            'forefoot': float,  # 鍓嶈冻鍘嬪姏鍗犳瘮(%)
            'midfoot': float,   # 涓冻鍘嬪姏鍗犳瘮(%)
            'hindfoot': float,  # 鍚庤冻鍘嬪姏鍗犳瘮(%)
        },
        'right': { ... 鍚屼笂 },
    }
    鍓嶇娓叉煋: ECharts 鏌辩姸鍥炬垨楗煎浘
    """
    ad = result.get('additional_data', {})
    lp = ad.get('left_pressure', {})
    rp = ad.get('right_pressure', {})

    def to_percent(p):
        return {
            'forefoot': (p.get('鍓嶈冻') or 0) * 100,
            'midfoot': (p.get('涓冻') or 0) * 100,
            'hindfoot': (p.get('鍚庤冻') or 0) * 100,
        }

    return {
        'left': to_percent(lp),
        'right': to_percent(rp),
    }


