def get_bilateral_pressure_ratio(result):
    """
    銆愭覆鏌撳尯鍩熴€戝乏鍙宠剼鍘嬪姏姣?(StandingReport.jsx #overview)

    娉ㄦ剰: 婧愮畻娉?calculate_region_pressures 鍙绠楁瘡鍙剼鍐呴儴鐨勫墠/涓?鍚庤冻姣斾緥锛?
    涓嶆彁渚涘乏鍙宠剼涔嬮棿鐨勬€诲帇鍔涘姣斻€傛鏂规硶閫氳繃 additional_data 涓殑
    left_area / right_area 鐨勬€婚潰绉繎浼间及绠楀乏鍙宠剼璐熼噸姣斻€?

    杩斿洖: {
        'leftRatio': float,   # 宸﹁剼鍘嬪姏鍗犳瘮(%)
        'rightRatio': float,  # 鍙宠剼鍘嬪姏鍗犳瘮(%)
    }
    鍓嶇娓叉煋: 杩涘害鏉℃垨楗煎浘
    """
    ad = result.get('additional_data', {})
    left_area_info = ad.get('left_area', {})
    right_area_info = ad.get('right_area', {})

    # 鐢ㄦ帴瑙﹂潰绉€诲拰浣滀负杩戜技璐熼噸鎸囨爣
    left_total = sum(left_area_info.get('area_cm2', [0, 0, 0]))
    right_total = sum(right_area_info.get('area_cm2', [0, 0, 0]))
    total = left_total + right_total

    if total > 0:
        left_ratio = round(left_total / total * 100, 1)
        return {
            'leftRatio': left_ratio,
            'rightRatio': round(100 - left_ratio, 1),
        }
    return {'leftRatio': 50.0, 'rightRatio': 50.0}


